const item = $input.first().json;

const from = item.From || item.from ||
  item.payload?.headers?.find(h => h.name === 'From')?.value || 'Unknown Sender';

const subject = item.Subject || item.subject ||
  item.payload?.headers?.find(h => h.name === 'Subject')?.value || '(No Subject)';

const bodyText = (item.snippet || '')
  .replace(/&amp;/g, '&').replace(/&#39;/g, "'")
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ').trim().substring(0, 1500);

const fromLower = from.toLowerCase();
const subjectLower = subject.toLowerCase();
const bodyLower = bodyText.toLowerCase();

const automatedSender =
  /no.?reply|donotreply|noreply/.test(fromLower) ||
  fromLower.includes('notifications@') ||
  fromLower.includes('mailer-daemon') ||
  fromLower.includes('postmaster@') ||
  fromLower.includes('bounce@') ||
  fromLower.includes('alerts@') ||
  fromLower.includes('automated@') ||
  fromLower.includes('-noreply@') ||
  fromLower.includes('daemon@');

const transactionalSubject =
  /transaction alert|debit alert|credit alert|payment receipt|account statement|otp|one.time.pass|bank alert|invoice #|order confirm|shipment|your receipt|purchase confirm|subscription renew|password reset|verify your|email verification|security alert|login attempt|sign.in alert|2fa|two.factor/.test(subjectLower);

const transactionalBody =
  /debit transaction|credit transaction|transaction of (pkr|usd|gbp|eur)|account no:|your account has been|was made in your account|available balance|txn id|transaction id|ref no|reference number/.test(bodyLower);

const skipEmail = automatedSender || transactionalSubject || transactionalBody;

return [{
  json: {
    messageId: item.id,
    threadId: item.threadId,
    from,
    subject,
    bodyText,
    receivedAt: new Date().toISOString(),
    skipEmail,
    skipReason: automatedSender ? 'automated_sender' : transactionalSubject ? 'transactional_subject' : transactionalBody ? 'transactional_body' : null
  }
}];

const email = $input.first().json;

const systemPrompt = `You are an intelligent email agent for a business. Read the incoming email, decide what to do, and write a short reply if needed.

Return ONLY valid JSON with exactly these fields:
- action: 'reply' or 'skip'
- category: 'inquiry', 'complaint', 'support', 'feedback', 'spam', or 'other'
- urgency: 'low', 'medium', or 'high'
- confidence: number between 0.0 and 1.0
- reply: the reply body text as a string, or empty string if action is skip

ACTION RULES:
- skip: spam, phishing, bulk marketing, newsletters, cold outreach, anything needing no reply
- reply: real human emails waiting for a response

REPLY RULES:
- Maximum 3 short sentences only
- complaint: empathetic, apologetic, solution-focused
- inquiry: direct and helpful
- support: patient and clear
- feedback: warm and grateful
- other: polite and neutral
- IMPORTANT: Do NOT invent prices, policies, account info, or any specific details you do not have
- If you cannot answer specifically, use exactly this text: Thank you for reaching out. Your request has been forwarded to our management team and we will get back to you shortly.
- Do NOT include a greeting or sign-off in the reply field`;

const userMessage = `Process this email:

From: ${email.from}
Subject: ${email.subject}
Message: ${email.bodyText}`;

const body = {
  model: 'llama-3.3-70b-versatile',
  temperature: 0.3,
  max_tokens: 400,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

return [{ json: { body: JSON.stringify(body), emailData: email } }];

const groqResponse = $input.first().json;
const emailData = $('Build Agent Prompt').first().json.emailData;

let action = 'skip';
let category = 'other';
let urgency = 'low';
let confidence = 0;
let replyText = '';

try {
  const parsed = JSON.parse(groqResponse.choices[0].message.content);
  action = (parsed.action || 'skip').toLowerCase().trim();
  category = (parsed.category || 'other').toLowerCase().trim();
  urgency = (parsed.urgency || 'low').toLowerCase().trim();
  confidence = parseFloat(parsed.confidence) || 0;
  replyText = (parsed.reply || '').trim();
} catch(e) {
  action = 'skip';
}

const fallback = 'Thank you for reaching out. Your request has been forwarded to our management team and we will get back to you shortly.';

if (action === 'reply' && !replyText) replyText = fallback;
if (action === 'reply' && confidence < 0.5) replyText = fallback;

const fromMatch = emailData.from.match(/^([^<@,"]+)/);
const senderName = (fromMatch ? fromMatch[1].trim().split(' ')[0] : 'there') || 'there';

return [{
  json: {
    action,
    category,
    urgency,
    confidence,
    replyText,
    senderName,
    messageId: emailData.messageId,
    threadId: emailData.threadId,
    from: emailData.from,
    subject: emailData.subject
  }
}];

const data = $input.first().json;

const fullBody = `Hi ${data.senderName},\n\n${data.replyText}\n\nBest regards,\nSupport Team`;

return [{
  json: {
    to: data.from,
    subject: 'Re: ' + data.subject,
    body: fullBody,
    threadId: data.threadId,
    category: data.category,
    urgency: data.urgency,
    originalMessageId: data.messageId
  }
}];
